module RefModule(
    input   [3:0]   a     ,
    input   [3:0]   b     ,

    output  [3:0]   sum   ,
    output          carry_out
);

   // Internal wire for carry
   wire [4:0] full_sum;

   // Perform the addition
     wire _n01 = a[0] ^ b[0];
  wire _c01 = a[0] & b[0];
  wire _n02 = a[1] ^ b[1] ^ _c01;
  wire _c02 = (a[1] & b[1]) | (a[1] & _c01) | (b[1] & _c01);
  wire _n03 = a[2] ^ b[2] ^ _c02;
  wire _c03 = (a[2] & b[2]) | (a[2] & _c02) | (b[2] & _c02);
  wire _n04 = a[3] ^ b[3] ^ _c03;
  wire _c04 = (a[3] & b[3]) | (a[3] & _c03) | (b[3] & _c03);
  assign full_sum = {_n01, _n02, _n03, _n04};

   // Assign the outputs
   assign sum = full_sum[3:0];
   assign carry_out = full_sum[4];

endmodule
